-
-  /// Print plain-text dump of this VPlan to \p O.
-  void print(raw_ostream &O) const {
-    VPSlotTracker SlotTracker(getPlan());
-    print(O, "", SlotTracker);
-  }
-
-  /// Print the successors of this block to \p O, prefixing all lines with \p
-  /// Indent.
