-  using VPBlocksTy = SmallVectorImpl<VPBlockBase *>;
-
-  virtual ~VPBlockBase() = default;
-
-  const std::string &getName() const { return Name; }
-
-  void setName(const Twine &newName) { Name = newName.str(); }
