-      VPValue *ResultVPV = R.getVPSingleValue();
-      auto *UI = cast_or_null<Instruction>(ResultVPV->getUnderlyingValue());
-      unsigned NewResSizeInBits = MinBWs.lookup(UI);
-      if (!NewResSizeInBits)
-        continue;
