-  Value *generatePerLane(VPTransformState &State, const VPLane &Lane);
-
-#if !defined(NDEBUG)
-  /// Return true if the VPInstruction is a floating point math operation, i.e.
-  /// has fast-math flags.
-  bool isFPMathOp() const;
-#endif
-
-public:
