-      using namespace llvm::VPlanPatternMatch;
-      if (OldResSizeInBits != NewResSizeInBits &&
-          !match(&R, m_Binary<Instruction::ICmp>(m_VPValue(), m_VPValue()))) {
-        // Extend result to original width.
