-  /// replaced by a new entry block created during skeleton creation.
-  VPBasicBlock *Entry;
-
-  /// VPIRBasicBlock wrapping the header of the original scalar loop.
-  VPIRBasicBlock *ScalarHeader;
-
-  /// Holds the VFs applicable to this VPlan.
