-  VPValue *BackedgeTakenCount = nullptr;
-
-  /// Represents the vector trip count.
-  VPValue VectorTripCount;
-
-  /// Represents the vectorization factor of the loop.
-  VPValue VF;
-
-  /// Represents the loop-invariant VF * UF of the vector loop region.
